3997	\begin{lemma}[Quasi-coherence datum: a cover with a presentation on each member]
3998	  \label{lem:quasicoherentData_mathlib}
3999	  \lean{SheafOfModules.QuasicoherentData}
4000	  \mathlibok
4001	  \textit{Provided by Mathlib.}
4002	  A \emph{quasi-coherence datum} for a sheaf of modules \(\mathcal{F}\) consists of a family of objects
4003	  \(U_i\) of the site that covers the terminal object, together with, for each \(i\), a presentation of
4004	  the over-picture restriction \(\mathcal{F}.\operatorname{over} U_i\). A sheaf of modules is
4005	  quasi-coherent precisely when such a datum exists.
4006	\end{lemma}
